import { createAuthPlugin } from "@better-auth-ui/core"
import {
  type ApiKeyPluginOptions,
  apiKeyPlugin as coreApiKeyPlugin
} from "@better-auth-ui/core/plugins/api-key"
import { OrganizationApiKeys } from "@/components/auth/api-key/organization-api-keys"

export const apiKeyPlugin = createAuthPlugin(
  coreApiKeyPlugin.id,
  (options: ApiKeyPluginOptions = {}) => {
    const core = coreApiKeyPlugin(options)

    return {
      ...core,
      ...(core.organization ? { organizationCards: [OrganizationApiKeys] } : {})
    }
  }
)

import type { ApiKeyAuthClient } from "@better-auth-ui/core/plugins/api-key"
import { apiKeyLocalization } from "@better-auth-ui/core/plugins/api-key"
import { useAuth } from "@better-auth-ui/solid"
import { useListApiKeys } from "@better-auth-ui/solid/plugins/api-key"
import { createSignal, For, Show } from "solid-js"
import { ApiKey } from "@/components/auth/api-key/api-key"
import { ApiKeySkeleton } from "@/components/auth/api-key/api-key-skeleton"
import { ApiKeysEmpty } from "@/components/auth/api-key/api-keys-empty"
import { CreateApiKeyDialog } from "@/components/auth/api-key/create-api-key-dialog"
import type { ListedApiKey } from "@/components/auth/settings/shared/types"
import { Button } from "@/components/ui/button"
import { Card, CardContent } from "@/components/ui/card"
import { Dialog, DialogTrigger } from "@/components/ui/dialog"
import { ItemSeparator } from "@/components/ui/item"
import { cn } from "@/lib/utils"

export type ApiKeysProps = {
  class?: string
  organizationId?: string
  isPending?: boolean
  hideCreate?: boolean
  hideDelete?: boolean
}

export function ApiKeys(props: ApiKeysProps = {}) {
  const auth = useAuth<ApiKeyAuthClient>()
  const [isCreateDialogOpen, setIsCreateDialogOpen] = createSignal(false)
  const listParams = () =>
    props.isPending !== undefined || props.organizationId
      ? {
          query: {
            organizationId: props.organizationId ?? "",
            configId: "organization" as const
          }
        }
      : undefined
  const apiKeys = useListApiKeys(auth.authClient, listParams())
  const keys = () => apiKeys.data?.apiKeys ?? []
  const pending = () => Boolean(props.isPending || apiKeys.isPending)

  return (
    <div class={cn("flex flex-col gap-3", props.class)}>
      <div class="flex items-end justify-between gap-3">
        <h2 class="truncate text-sm font-semibold">
          {apiKeyLocalization.apiKeys}
        </h2>
        <Show when={!props.hideCreate}>
          <Dialog
            open={isCreateDialogOpen()}
            onOpenChange={setIsCreateDialogOpen}
          >
            <DialogTrigger
              as={Button}
              class="shrink-0"
              disabled={pending()}
              size="sm"
            >
              {apiKeyLocalization.createApiKey}
            </DialogTrigger>
            <CreateApiKeyDialog
              organizationId={props.organizationId}
              onOpenChange={setIsCreateDialogOpen}
            />
          </Dialog>
        </Show>
      </div>

      <Card class="z-card-padding-none">
        <CardContent class="z-card-content-padding-none">
          <Show when={!pending()} fallback={<ApiKeySkeleton />}>
            <Show
              when={keys().length > 0}
              fallback={
                <ApiKeysEmpty
                  hideCreate={props.hideCreate}
                  onCreatePress={() => setIsCreateDialogOpen(true)}
                />
              }
            >
              <For each={keys()}>
                {(apiKey, index) => (
                  <>
                    <Show when={index() > 0}>
                      <ItemSeparator />
                    </Show>
                    <ApiKey
                      apiKey={apiKey as ListedApiKey}
                      hideDelete={props.hideDelete}
                      organizationId={props.organizationId}
                    />
                  </>
                )}
              </For>
            </Show>
          </Show>
        </CardContent>
      </Card>
    </div>
  )
}

export const ApiKeysSettings = ApiKeys

import { apiKeyLocalization } from "@better-auth-ui/core/plugins/api-key"
import { useAuth } from "@better-auth-ui/solid"
import { Key, X } from "lucide-solid"
import { createSignal, Show } from "solid-js"
import { DeleteApiKeyDialog } from "@/components/auth/api-key/delete-api-key-dialog"
import type { ListedApiKey } from "@/components/auth/settings/shared/types"
import { Button } from "@/components/ui/button"
import { Dialog, DialogTrigger } from "@/components/ui/dialog"

export function ApiKey(props: {
  apiKey: ListedApiKey
  organizationId?: string
  hideDelete?: boolean
}) {
  const auth = useAuth()
  const [deleteOpen, setDeleteOpen] = createSignal(false)
  const preview = () => `${props.apiKey.start}${"*".repeat(16)}`

  return (
    <div class="flex items-center gap-3 p-6">
      <div class="flex size-10 shrink-0 items-center justify-center rounded-md bg-muted">
        <Key class="size-4.5" />
      </div>

      <div class="flex min-w-0 flex-col">
        <span class="truncate font-medium text-sm leading-tight">
          {props.apiKey.name || apiKeyLocalization.apiKey}
        </span>
        <span class="truncate font-mono text-muted-foreground text-xs">
          {preview()}
        </span>
        <span class="text-muted-foreground text-xs">
          {new Date(props.apiKey.createdAt).toLocaleString(undefined, {
            dateStyle: "medium",
            timeStyle: "short"
          })}
        </span>
      </div>

      <Show when={!props.hideDelete}>
        <Dialog open={deleteOpen()} onOpenChange={setDeleteOpen}>
          <DialogTrigger
            as={Button}
            aria-label={apiKeyLocalization.deleteApiKey}
            class="ml-auto shrink-0"
            size="sm"
            variant="outline"
          >
            <X />
            {auth.localization.settings.delete}
          </DialogTrigger>
          <DeleteApiKeyDialog
            apiKey={props.apiKey}
            organizationId={props.organizationId}
            onOpenChange={setDeleteOpen}
          />
        </Dialog>
      </Show>
    </div>
  )
}

import type { OrganizationAuthClient } from "@better-auth-ui/core/plugins/organization"
import { useAuth, useSession } from "@better-auth-ui/solid"
import {
  useActiveOrganization,
  useListOrganizationMembers
} from "@better-auth-ui/solid/plugins/organization"
import { createMemo, Show } from "solid-js"
import { ApiKeys } from "@/components/auth/api-key/api-keys"

export type OrganizationApiKeysProps = {
  class?: string
}

/**
 * {@link ApiKeys} scoped to the active organization.
 *
 * Hidden for members whose role isn't `owner`. Better Auth's
 * `/organization/has-permission` endpoint isn't usable for `apiKey:*` checks
 * (it doesn't pass `allowCreatorAllPermissions` and the default org AC has no
 * `apiKey` statements), so we gate on role directly.
 */
export function OrganizationApiKeys(props: OrganizationApiKeysProps) {
  const auth = useAuth<OrganizationAuthClient>()
  const session = useSession(auth.authClient)
  const activeOrganization = useActiveOrganization(auth.authClient)
  const members = useListOrganizationMembers(auth.authClient)
  const canManageApiKeys = createMemo(() =>
    Boolean(
      members.data?.members.some(
        (member: { role?: string | null; userId?: string | null }) =>
          member.role === "owner" && member.userId === session.data?.user.id
      )
    )
  )

  return (
    <Show when={canManageApiKeys()}>
      <ApiKeys
        class={props.class}
        organizationId={activeOrganization.data?.id}
        isPending={activeOrganization.isPending}
      />
    </Show>
  )
}

import { Skeleton } from "@/components/ui/skeleton"

export function ApiKeySkeleton() {
  return (
    <div class="flex items-center gap-3 p-4">
      <Skeleton class="size-10 rounded-md" />
      <div class="flex flex-col gap-1">
        <Skeleton class="h-4 w-28" />
        <Skeleton class="h-3 w-36" />
        <Skeleton class="h-3 w-32" />
      </div>
    </div>
  )
}

import type { ApiKeyAuthClient } from "@better-auth-ui/core/plugins/api-key"
import { apiKeyLocalization } from "@better-auth-ui/core/plugins/api-key"
import { useAuth } from "@better-auth-ui/solid"
import { useCreateApiKey } from "@better-auth-ui/solid/plugins/api-key"
import { Key } from "lucide-solid"
import { createSignal } from "solid-js"
import { NewApiKeyDialog } from "@/components/auth/api-key/new-api-key-dialog"
import { Button } from "@/components/ui/button"
import {
  Dialog,
  DialogClose,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle
} from "@/components/ui/dialog"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"

export function CreateApiKeyDialog(props: {
  organizationId?: string
  onOpenChange: (open: boolean) => void
}) {
  const auth = useAuth<ApiKeyAuthClient>()
  const [isNewKeyDialogOpen, setIsNewKeyDialogOpen] = createSignal(false)
  const [newApiKeyName, setNewApiKeyName] = createSignal<string | null>(null)
  const [newApiKeySecret, setNewApiKeySecret] = createSignal<string | null>(
    null
  )
  const createApiKey = useCreateApiKey(auth.authClient, {
    onSuccess: (apiKey) => {
      props.onOpenChange(false)
      setNewApiKeyName(apiKey.name ?? null)
      setNewApiKeySecret(apiKey.key)
      setIsNewKeyDialogOpen(true)
    }
  })

  const submitCreateApiKey = (event: SubmitEvent) => {
    event.preventDefault()

    const formData = new FormData(event.currentTarget as HTMLFormElement)
    const name = String(formData.get("name") ?? "").trim()
    const payload = {
      ...(name ? { name } : {}),
      ...(props.organizationId
        ? { organizationId: props.organizationId, configId: "organization" }
        : {})
    }

    createApiKey.mutate(
      (Object.keys(payload).length > 0 ? payload : undefined) as Parameters<
        typeof createApiKey.mutate
      >[0]
    )
  }

  return (
    <>
      <DialogContent>
        <form class="flex flex-col gap-6" onSubmit={submitCreateApiKey}>
          <DialogHeader>
            <div class="flex size-10 items-center justify-center rounded-md bg-muted">
              <Key class="size-4.5" />
            </div>
            <DialogTitle>{apiKeyLocalization.createApiKey}</DialogTitle>
            <DialogDescription>
              {apiKeyLocalization.apiKeysDescription}
            </DialogDescription>
          </DialogHeader>

          <div class="grid gap-2">
            <Label for="api-key-name">{apiKeyLocalization.name}</Label>
            <Input
              autofocus
              disabled={createApiKey.isPending}
              id="api-key-name"
              name="name"
              placeholder={auth.localization.settings.optional}
            />
          </div>

          <DialogFooter>
            <DialogClose
              as={Button}
              disabled={createApiKey.isPending}
              type="button"
              variant="outline"
            >
              {auth.localization.settings.cancel}
            </DialogClose>
            <Button disabled={createApiKey.isPending} type="submit">
              {createApiKey.isPending
                ? `${apiKeyLocalization.createApiKey}…`
                : apiKeyLocalization.createApiKey}
            </Button>
          </DialogFooter>
        </form>
      </DialogContent>

      <Dialog open={isNewKeyDialogOpen()} onOpenChange={setIsNewKeyDialogOpen}>
        <NewApiKeyDialog name={newApiKeyName()} secretKey={newApiKeySecret()} />
      </Dialog>
    </>
  )
}

import type { ApiKeyAuthClient } from "@better-auth-ui/core/plugins/api-key"
import { apiKeyLocalization } from "@better-auth-ui/core/plugins/api-key"
import { useAuth } from "@better-auth-ui/solid"
import { useDeleteApiKey } from "@better-auth-ui/solid/plugins/api-key"
import { Key } from "lucide-solid"
import type { ListedApiKey } from "@/components/auth/settings/shared/types"
import { Button } from "@/components/ui/button"
import {
  DialogClose,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle
} from "@/components/ui/dialog"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"

export function DeleteApiKeyDialog(props: {
  apiKey: ListedApiKey
  organizationId?: string
  onOpenChange: (open: boolean) => void
}) {
  const auth = useAuth<ApiKeyAuthClient>()
  const preview = () => `${props.apiKey.start}${"*".repeat(16)}`
  const previewId = () => `delete-api-key-preview-${props.apiKey.id}`
  const deleteApiKey = useDeleteApiKey(auth.authClient, {
    onSuccess: () => props.onOpenChange(false)
  })

  const deleteKey = () => {
    deleteApiKey.mutate({
      keyId: props.apiKey.id,
      ...(props.organizationId ? { configId: "organization" } : {})
    } as Parameters<typeof deleteApiKey.mutate>[0])
  }

  return (
    <DialogContent>
      <DialogHeader>
        <div class="flex size-10 items-center justify-center rounded-md bg-muted">
          <Key class="size-4.5" />
        </div>
        <DialogTitle>{apiKeyLocalization.deleteApiKey}</DialogTitle>
        <DialogDescription>
          {apiKeyLocalization.deleteApiKeyWarning}
        </DialogDescription>
      </DialogHeader>

      <div class="grid gap-2">
        <Label for={previewId()}>
          {props.apiKey.name || apiKeyLocalization.apiKey}
        </Label>
        <Input
          class="font-mono text-xs"
          disabled
          id={previewId()}
          readonly
          value={preview()}
        />
      </div>

      <DialogFooter>
        <DialogClose
          as={Button}
          disabled={deleteApiKey.isPending}
          type="button"
          variant="outline"
        >
          {auth.localization.settings.cancel}
        </DialogClose>
        <Button
          disabled={deleteApiKey.isPending}
          onClick={deleteKey}
          type="button"
          variant="destructive"
        >
          {deleteApiKey.isPending
            ? `${apiKeyLocalization.deleteApiKey}…`
            : apiKeyLocalization.deleteApiKey}
        </Button>
      </DialogFooter>
    </DialogContent>
  )
}

import { type ClassValue, clsx } from "clsx"
import { twMerge } from "tailwind-merge"

export const cn = (...inputs: ClassValue[]) => twMerge(clsx(inputs))
